/**
 * Create an editor for a target node. Returns a factory
 * for the target's kind, pre-loaded with its byte range.
 * Call .toEdit() with no args to produce the Edit.
 */
export function edit<K extends string>(target: ReplaceTarget<K>): any {
  const fields: any = {};
  const node: any = { type: target.type, fields };
  const fieldSetters: Record<string, string[]> = {
    'abstract_type': ['trait', 'children'],
    'arguments': ['children'],
    'array_expression': ['length', 'children'],
    'array_type': ['element', 'length'],
    'assignment_expression': ['left', 'right'],
    'associated_type': ['name', 'typeParameters', 'bounds', 'children'],
    'async_block': ['children'],
    'attribute': ['value', 'arguments', 'children'],
    'attribute_item': ['children'],
    'await_expression': ['children'],
    'base_field_initializer': ['children'],
    'binary_expression': ['left', 'operator', 'right'],
    'block': ['children'],
    'block_comment': ['outer', 'inner', 'doc'],
    'bounded_type': ['children'],
    'bracketed_type': ['children'],
    'break_expression': ['children'],
    'call_expression': ['function', 'arguments'],
    'captured_pattern': ['children'],
    'closure_expression': ['parameters', 'returnType', 'body'],
    'closure_parameters': ['children'],
    'compound_assignment_expr': ['left', 'operator', 'right'],
    'const_block': ['body'],
    'const_item': ['name', 'typeField', 'value', 'children'],
    'const_parameter': ['name', 'typeField', 'value'],
    'continue_expression': ['children'],
    'declaration_list': ['children'],
    'dynamic_type': ['trait'],
    'else_clause': ['children'],
    'enum_item': ['name', 'typeParameters', 'body', 'children'],
    'enum_variant': ['name', 'body', 'value', 'children'],
    'enum_variant_list': ['children'],
    'expression_statement': ['children'],
    'extern_crate_declaration': ['name', 'alias', 'children'],
    'extern_modifier': ['children'],
    'field_declaration': ['name', 'typeField', 'children'],
    'field_declaration_list': ['children'],
    'field_expression': ['value', 'field'],
    'field_initializer': ['field', 'value', 'children'],
    'field_initializer_list': ['children'],
    'field_pattern': ['name', 'pattern', 'children'],
    'for_expression': ['pattern', 'value', 'body', 'children'],
    'for_lifetimes': ['children'],
    'foreign_mod_item': ['body', 'children'],
    'function_item': ['name', 'typeParameters', 'parameters', 'returnType', 'body', 'children'],
    'function_modifiers': ['children'],
    'function_signature_item': ['name', 'typeParameters', 'parameters', 'returnType', 'children'],
    'function_type': ['trait', 'parameters', 'returnType', 'children'],
    'gen_block': ['children'],
    'generic_function': ['function', 'typeArguments'],
    'generic_pattern': ['typeArguments', 'children'],
    'generic_type': ['typeField', 'typeArguments'],
    'generic_type_with_turbofish': ['typeField', 'typeArguments'],
    'higher_ranked_trait_bound': ['typeParameters', 'typeField'],
    'if_expression': ['condition', 'consequence', 'alternative'],
    'impl_item': ['typeParameters', 'trait', 'typeField', 'body', 'children'],
    'index_expression': ['children'],
    'inner_attribute_item': ['children'],
    'label': ['children'],
    'let_chain': ['children'],
    'let_condition': ['pattern', 'value'],
    'let_declaration': ['pattern', 'typeField', 'value', 'alternative', 'children'],
    'lifetime': ['children'],
    'lifetime_parameter': ['name', 'bounds'],
    'line_comment': ['outer', 'inner', 'doc'],
    'loop_expression': ['body', 'children'],
    'macro_definition': ['name', 'children'],
    'macro_invocation': ['macro', 'children'],
    'macro_rule': ['left', 'right'],
    'match_arm': ['pattern', 'value', 'children'],
    'match_block': ['children'],
    'match_expression': ['value', 'body'],
    'match_pattern': ['condition', 'children'],
    'mod_item': ['name', 'body', 'children'],
    'mut_pattern': ['children'],
    'negative_literal': ['children'],
    'or_pattern': ['children'],
    'ordered_field_declaration_list': ['typeField', 'children'],
    'parameter': ['pattern', 'typeField', 'children'],
    'parameters': ['children'],
    'parenthesized_expression': ['children'],
    'pointer_type': ['typeField', 'children'],
    'qualified_type': ['typeField', 'alias'],
    'range_expression': ['children'],
    'range_pattern': ['left', 'right'],
    'raw_string_literal': ['children'],
    'ref_pattern': ['children'],
    'reference_expression': ['value', 'children'],
    'reference_pattern': ['children'],
    'reference_type': ['typeField', 'children'],
    'removed_trait_bound': ['children'],
    'return_expression': ['children'],
    'scoped_identifier': ['path', 'name'],
    'scoped_type_identifier': ['path', 'name'],
    'scoped_use_list': ['path', 'list'],
    'self_parameter': ['children'],
    'shorthand_field_initializer': ['children'],
    'slice_pattern': ['children'],
    'source_file': ['children'],
    'static_item': ['name', 'typeField', 'value', 'children'],
    'string_literal': ['children'],
    'struct_expression': ['name', 'body'],
    'struct_item': ['name', 'typeParameters', 'body', 'children'],
    'struct_pattern': ['typeField', 'children'],
    'token_binding_pattern': ['name', 'typeField'],
    'token_repetition': ['children'],
    'token_repetition_pattern': ['children'],
    'token_tree': ['children'],
    'token_tree_pattern': ['children'],
    'trait_bounds': ['children'],
    'trait_item': ['name', 'typeParameters', 'bounds', 'body', 'children'],
    'try_block': ['children'],
    'try_expression': ['children'],
    'tuple_expression': ['children'],
    'tuple_pattern': ['children'],
    'tuple_struct_pattern': ['typeField', 'children'],
    'tuple_type': ['children'],
    'type_arguments': ['children'],
    'type_binding': ['name', 'typeArguments', 'typeField'],
    'type_cast_expression': ['value', 'typeField'],
    'type_item': ['name', 'typeParameters', 'typeField', 'children'],
    'type_parameter': ['name', 'bounds', 'defaultType'],
    'type_parameters': ['children'],
    'unary_expression': ['children'],
    'union_item': ['name', 'typeParameters', 'body', 'children'],
    'unsafe_block': ['children'],
    'use_as_clause': ['path', 'alias'],
    'use_bounds': ['children'],
    'use_declaration': ['argument', 'children'],
    'use_list': ['children'],
    'use_wildcard': ['children'],
    'variadic_parameter': ['pattern', 'children'],
    'visibility_modifier': ['children'],
    'where_clause': ['children'],
    'where_predicate': ['left', 'bounds'],
    'while_expression': ['condition', 'body', 'children'],
    'yield_expression': ['children'],
  };
  const names = fieldSetters[target.type] ?? [];
  // Map setter names back to grammar field names
  const fieldNameMap: Record<string, string> = { typeField: "type" };
  for (const name of names) {
    const grammarName = fieldNameMap[name] ?? name;
    node[name] = (...v: any[]) => { fields[grammarName] = v.length === 1 ? resolveInput(v[0]) : v; return node; };
  }
  node.render = () => render(node, rules, joinBy);
  return bindRange(target, node);
}
